    signedBy: "Nguyễn Phú Trọng",
    issuedDate: "2010-06-16",
    effectiveDate: "2011-01-01",
    expiryDate: "2024-07-01",
    replacedBy: "32/2024/QH15",
    status: "Hết hiệu lực từ 01/07/2024",
